func transferFunds(ctx context.Context, from, to string, amount int) (retErr error) {
    tx, err := db.BeginTx(ctx, nil)
    if err != nil {
        return fmt.Errorf("begin tx: %w", err)
    }
    defer func() {
        if retErr != nil {
            if rbErr := tx.Rollback(); rbErr != nil {
                retErr = fmt.Errorf("%w (rollback also failed: %v)", retErr, rbErr)
            }
        }
    }()
    // ... do work ...
    if err := tx.Commit(); err != nil {
        return fmt.Errorf("commit: %w", err)
    }
    return nil
}

