type Server struct {
    notifications chan Event
    wg           sync.WaitGroup
}

func (s *Server) Start(ctx context.Context) {
    s.wg.Add(1)
    go func() {
        defer s.wg.Done()
        for {
            select {
            case <-ctx.Done():
                return
            case ev := <-s.notifications:
                sendNotification(ctx, ev)
            }
        }
    }()
}

func (s *Server) Stop() { s.wg.Wait() }

