// Bug in Go < 1.22: all goroutines see the last value of item
for _, item := range items {
    go func() {
        process(item) // captures loop variable by reference
    }()
}

// Safe in all Go versions: pass loop variable as parameter
for _, item := range items {
    go func(it Item) {
        process(it)
    }(item)
}

// In Go 1.22+, the loop variable is per-iteration, so this is also safe:
// for _, item := range items {
//     go func() { process(item) }()
// }

var wg sync.WaitGroup
for _, item := range items {
    go func(it Item) {
        wg.Add(1) // RACE: wg.Wait() may return before this runs
        defer wg.Done()
        process(it)
    }(item)
}
wg.Wait()

var wg sync.WaitGroup
for _, item := range items {
    wg.Add(1) // Called BEFORE the go statement
    go func(it Item) {
        defer wg.Done()
        process(it)
    }(item)
}
wg.Wait()

// Unbounded: spawns one goroutine per item
for _, item := range items {
    go process(item)
}

// Bounded worker pool using a semaphore
sem := make(chan struct{}, 10) // max 10 concurrent
var wg sync.WaitGroup
for _, item := range items {
    wg.Add(1)
    sem <- struct{}{} // acquire
    go func(it Item) {
        defer wg.Done()
        defer func() { <-sem }() // release
        process(it)
    }(item)
}
wg.Wait()

