    select {
    case msg := <-ch:
        handle(msg)
    default:
        // spins at 100% CPU
    }
}

// Blocking select - efficient
for {
    select {
    case msg := <-ch:
        handle(msg)
    case <-ctx.Done():
        return
    }
}

