func handler(w http.ResponseWriter, r *http.Request) {
    key := r.URL.Query().Get("key")
    if v, ok := cache[key]; ok { // concurrent read - may crash
        json.NewEncoder(w).Encode(v)
        return
    }
    result := compute(key)
    cache[key] = result // concurrent write - WILL crash
}

var (
    cache   = make(map[string]*Result)
    cacheMu sync.RWMutex
)

func handler(w http.ResponseWriter, r *http.Request) {
    key := r.URL.Query().Get("key")
    cacheMu.RLock()
    v, ok := cache[key]
    cacheMu.RUnlock()
    if ok {
        json.NewEncoder(w).Encode(v)
        return
    }
    result := compute(key)
    cacheMu.Lock()
    cache[key] = result
    cacheMu.Unlock()
}

