    if order.IsFirstOrder {
        return 0.10
    }
    return 0.0
}

// calculateDiscount applies the tiered discount policy:
// - 15% for orders over $100 with 5+ items (bulk discount, per PRICING-2024-Q1)
// - 10% for first-time customers (acquisition incentive, per GROWTH-123)
// - Discounts do not stack; bulk discount takes priority.
func calculateDiscount(order *Order) float64 {
    if order.Total > 100 && order.Items > 5 {
        return 0.15
    }
    if order.IsFirstOrder {
        return 0.10
    }
    return 0.0
}

